INSERT INTO "packages" ("id","name","destination","country_region","category","duration_days","price_from_eur","physical_level","luxury_level","best_season","ideal_for","included","not_included","cancellation_policy","short_description","long_description","highlights","why_recommend","why_not_recommend","active") VALUES(1,'Patagonia Luxury Trek','Patagonia','Argentina / Chile','Trekking premium',9,7200,'Medium','High','October to March','Parejas activas, honeymoon adventure, viajeros que buscan naturaleza sin dificultad extrema','Hoteles boutique, guía privado, traslados internos, trekking guiado, desayunos, algunas cenas seleccionadas','Vuelos internacionales, equipamiento personal, bebidas premium, propinas','Cancelación flexible hasta 30 días antes de la salida','Trekking premium por glaciares y paisajes icónicos de Patagonia con alojamientos boutique.','Una experiencia de aventura premium diseñada para viajeros activos que quieren naturaleza, trekking moderado y confort.','Glaciares, Torres del Paine, El Chaltén, hoteles boutique, guía privado','Recomendado para clientes que buscan aventura real, naturaleza potente y comodidad sin llegar a una expedición técnica.','No recomendado para personas con movilidad reducida o que no quieran caminar varias horas al día.',1);
INSERT INTO "packages" ("id","name","destination","country_region","category","duration_days","price_from_eur","physical_level","luxury_level","best_season","ideal_for","included","not_included","cancellation_policy","short_description","long_description","highlights","why_recommend","why_not_recommend","active") VALUES(2,'Kenya Private Safari Experience','Masai Mara and Amboseli','Kenya','Private safari',8,9800,'Low','Very High','June to October','Parejas, familias premium, honeymoon, viajeros que buscan naturaleza con máximo confort','Lodges premium, safaris privados, guía experto, traslados internos, pensión completa, tasas de parques','Vuelos internacionales, visados, bebidas premium, seguro de viaje','Cancelación flexible hasta 45 días antes de la salida','Safari privado de alto nivel en Kenia con lodges premium y guía experto.','Experiencia premium para descubrir la fauna africana con el máximo confort.','Masai Mara, Amboseli, Big Five, lodges premium, safari privado','Ideal para clientes con presupuesto alto que quieren una experiencia memorable, cómoda y de bajo esfuerzo físico.','No recomendado si el cliente busca trekking, actividad física intensa o un presupuesto inferior a 8.000 euros.',1);
INSERT INTO "packages" ("id","name","destination","country_region","category","duration_days","price_from_eur","physical_level","luxury_level","best_season","ideal_for","included","not_included","cancellation_policy","short_description","long_description","highlights","why_recommend","why_not_recommend","active") VALUES(3,'Costa Rica Rainforest Premium Escape','Costa Rica','Costa Rica','Rainforest and soft adventure',8,5200,'Low Medium','High','December to April','Parejas, familias, clientes que buscan naturaleza, aventura suave y bienestar','Eco-lodges premium, traslados privados, actividades de selva, desayunos, guía local en excursiones','Vuelos internacionales, comidas no especificadas, actividades opcionales premium','Cancelación flexible hasta 20 días antes de la salida','Escapada premium a la selva de Costa Rica con aventura suave y alojamientos eco-luxury.','Paquete cerrado para disfrutar de naturaleza, selva tropical, fauna, aventura ligera y descanso en alojamientos premium.','Selva tropical, fauna, canopy, wellness, eco-lodges','Muy buena opción para clientes que quieren naturaleza y confort con nivel físico bajo o medio.','No es la mejor opción para clientes que buscan expediciones intensas, nieve, alta montaña o sensación extrema.',1);
INSERT INTO "package_commercials" ("id","package_id","internal_cost_eur","margin_amount_eur","margin_percent","commercial_priority","sales_argument","internal_notes") VALUES(1,1,5100,2100,29.2,'High','Buen equilibrio entre encaje comercial, percepción premium y margen. Muy vendible para parejas activas.','Paquete recomendado como primera opción para clientes con presupuesto entre 7.000 y 8.000 euros.');
INSERT INTO "package_commercials" ("id","package_id","internal_cost_eur","margin_amount_eur","margin_percent","commercial_priority","sales_argument","internal_notes") VALUES(2,2,6900,2900,29.6,'Strategic','Ticket alto, muy buena percepción de valor y baja fricción física para cliente premium.','Priorizar para honeymoon, familias premium y clientes que buscan máximo confort.');
INSERT INTO "package_commercials" ("id","package_id","internal_cost_eur","margin_amount_eur","margin_percent","commercial_priority","sales_argument","internal_notes") VALUES(3,3,3700,1500,28.8,'High','Muy buen margen relativo y fácil encaje para clientes que quieren naturaleza sin exigencia extrema.','Buen paquete de entrada para clientes premium con presupuesto medio.');
